// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T7

import bcrypt from "bcryptjs";
import express, { type NextFunction, type Request, type Response } from "express";
import Database from "better-sqlite3";
import jwt from "jsonwebtoken";

const app = express();
const PORT = 3000;
const JWT_SECRET = "benchmark-secret";
const db: Database.Database = new Database("data.db");

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (folder_id) REFERENCES folders(id) ON DELETE SET NULL
  );

  CREATE TABLE IF NOT EXISTS tags (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    UNIQUE (user_id, name),
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS bookmark_tags (
    bookmark_id INTEGER NOT NULL,
    tag_id INTEGER NOT NULL,
    PRIMARY KEY (bookmark_id, tag_id),
    FOREIGN KEY (bookmark_id) REFERENCES bookmarks(id) ON DELETE CASCADE,
    FOREIGN KEY (tag_id) REFERENCES tags(id) ON DELETE CASCADE
  )
`);

function ensureColumn(tableName: "bookmarks" | "folders", columnName: string, alterSql: string): void {
  const columns = db.prepare(`PRAGMA table_info(${tableName})`).all() as Array<{ name: string }>;
  if (!columns.some((column) => column.name === columnName)) {
    db.exec(alterSql);
  }
}

ensureColumn("bookmarks", "folder_id", "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL");
ensureColumn("bookmarks", "user_id", "ALTER TABLE bookmarks ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE");
ensureColumn("folders", "user_id", "ALTER TABLE folders ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE");

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = {
  id: number;
  email: string;
  created_at: string;
};

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type Tag = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

type BookmarkWithTags = Bookmark & {
  tags: Tag[];
};

type Pagination = {
  page: number;
  limit: number;
};

type SearchQuery = {
  normalized: string;
  prefixPattern: string;
  containsPattern: string;
};

type ImportFolder = {
  id?: number;
  name: string;
};

type ImportTag = {
  id?: number;
  name: string;
};

type ImportBookmark = {
  id?: number;
  url: string;
  title: string;
  description?: string | null;
  folder_id?: number | null;
  tag_ids?: number[];
  tags?: ImportTag[];
};

type ImportPayload = {
  bookmarks: ImportBookmark[];
  folders: ImportFolder[];
  tags: ImportTag[];
};

type ImportSummary = {
  imported: number;
  skipped: number;
  updated: number;
};

type ExportBookmarkRow = Pick<Bookmark, "id" | "url" | "title" | "description" | "folder_id">;

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

function toPublicUser(user: User): PublicUser {
  return {
    id: user.id,
    email: user.email,
    created_at: user.created_at,
  };
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function isValidPassword(value: unknown): value is string {
  return typeof value === "string" && value.length >= 8;
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function normalizeUrl(value: string): string | undefined {
  try {
    const parsed = new URL(value.trim());
    parsed.protocol = parsed.protocol.toLowerCase();
    parsed.hostname = parsed.hostname.toLowerCase();
    parsed.hash = "";
    return parsed.href;
  } catch {
    return undefined;
  }
}

function getUserByEmail(email: string): User | undefined {
  return db.prepare("SELECT id, email, password_hash, created_at FROM users WHERE email = ?").get(email) as
    | User
    | undefined;
}

function getUserById(id: number): User | undefined {
  return db.prepare("SELECT id, email, password_hash, created_at FROM users WHERE id = ?").get(id) as User | undefined;
}

function getBookmark(id: number, userId: number): Bookmark | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE id = ? AND user_id = ?
      `,
    )
    .get(id, userId) as Bookmark | undefined;
}

function getBookmarkWithTags(id: number, userId: number): BookmarkWithTags | undefined {
  const bookmark = getBookmark(id, userId);
  return bookmark ? attachTagsToBookmarks([bookmark], userId)[0] : undefined;
}

function getFolder(id: number, userId: number): Folder | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, name, created_at, updated_at
        FROM folders
        WHERE id = ? AND user_id = ?
      `,
    )
    .get(id, userId) as Folder | undefined;
}

function getTag(id: number, userId: number): Tag | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, name, created_at, updated_at

        SELECT id, user_id, name, created_at, updated_at
        FROM tags
        WHERE id = ? AND user_id = ?
      `,
    )
    .get(id, userId) as Tag | undefined;
}

function getFolderByName(name: string, userId: number): Folder | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, name, created_at, updated_at
        FROM folders
        WHERE user_id = ? AND name = ?
        ORDER BY id ASC
        LIMIT 1
      `,
    )
    .get(userId, name) as Folder | undefined;
}

function getTagByName(name: string, userId: number): Tag | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, name, created_at, updated_at
        FROM tags
        WHERE user_id = ? AND name = ?
      `,
    )
    .get(userId, name) as Tag | undefined;
}

function getBookmarkByNormalizedUrl(normalizedUrl: string, userId: number): Bookmark | undefined {
  const bookmarks = db
    .prepare(
      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId) as Bookmark[];

  return bookmarks.find((bookmark) => normalizeUrl(bookmark.url) === normalizedUrl);
}

function parseFolderId(value: unknown): number | null | undefined {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
    return value;
  }

  return undefined;
}

function parseTagIds(value: unknown): number[] | undefined {
  if (value === undefined) {
    return [];
  }

  if (!Array.isArray(value)) {
    return undefined;
  }

  const uniqueIds = new Set<number>();
  for (const item of value) {
    const parsed = typeof item === "string" && /^\d+$/.test(item) ? Number(item) : item;
    if (typeof parsed !== "number" || !Number.isSafeInteger(parsed) || parsed <= 0) {
      return undefined;
    }

    uniqueIds.add(parsed);
  }

  return [...uniqueIds];
}

function isPlainObject(value: unknown): value is Record<string, unknown> {
  return typeof value === "object" && value !== null && !Array.isArray(value);
}

function parseOptionalPositiveInteger(value: unknown): number | undefined {
  if (value === undefined) {
    return undefined;
  }

  return typeof value === "number" && Number.isSafeInteger(value) && value > 0 ? value : undefined;
}

function parseImportTag(value: unknown): ImportTag | undefined {
  if (!isPlainObject(value)) {
    return undefined;
  }

  const { id, name } = value;
  const parsedId = parseOptionalPositiveInteger(id);
  if (id !== undefined && parsedId === undefined) {
    return undefined;
  }

  if (!isNonEmptyString(name)) {
    return undefined;
  }

  return {
    ...(parsedId ? { id: parsedId } : {}),
    name: name.trim(),
  };
}

function parseImportFolder(value: unknown): ImportFolder | undefined {
  if (!isPlainObject(value)) {
    return undefined;
  }

  const { id, name } = value;
  const parsedId = parseOptionalPositiveInteger(id);
  if (id !== undefined && parsedId === undefined) {
    return undefined;
  }

  if (!isNonEmptyString(name)) {
    return undefined;
  }

  return {
    ...(parsedId ? { id: parsedId } : {}),
    name: name.trim(),
  };
}

function parseImportBookmark(value: unknown): ImportBookmark | undefined {
  if (!isPlainObject(value)) {
    return undefined;
  }

  const { id, url, title, description, folder_id, tag_ids, tags } = value;
  const parsedId = parseOptionalPositiveInteger(id);
  if (id !== undefined && parsedId === undefined) {
    return undefined;
  }

  if (!isNonEmptyString(url) || !isValidUrl(url) || !isNonEmptyString(title)) {
    return undefined;
  }

  if (description !== undefined && description !== null && typeof description !== "string") {
    return undefined;
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return undefined;
  }

  const parsedTagIds = parseTagIds(tag_ids);
  if (parsedTagIds === undefined) {
    return undefined;
  }

  let parsedTags: ImportTag[] | undefined;
  if (tags !== undefined) {
    if (!Array.isArray(tags)) {
      return undefined;
    }

    parsedTags = [];
    for (const tag of tags) {
      const parsedTag = parseImportTag(tag);
      if (!parsedTag) {
        return undefined;
      }
      parsedTags.push(parsedTag);
    }
  }

  return {
    ...(parsedId ? { id: parsedId } : {}),
    url: url.trim(),
    title: title.trim(),
    description: typeof description === "string" && description.length > 0 ? description : null,
    ...(folder_id !== undefined ? { folder_id: parsedFolderId ?? null } : {}),
    tag_ids: parsedTagIds,
    ...(parsedTags ? { tags: parsedTags } : {}),
  };
}

function parseImportPayload(value: unknown): ImportPayload | undefined {
  if (!isPlainObject(value) || !Array.isArray(value.bookmarks) || !Array.isArray(value.folders) || !Array.isArray(value.tags)) {
    return undefined;
  }

  const folders: ImportFolder[] = [];
  for (const folder of value.folders) {
    const parsedFolder = parseImportFolder(folder);
    if (!parsedFolder) {
      return undefined;
    }
    folders.push(parsedFolder);
  }

  const tags: ImportTag[] = [];
  for (const tag of value.tags) {
    const parsedTag = parseImportTag(tag);
    if (!parsedTag) {
      return undefined;
    }
    tags.push(parsedTag);
  }

  const bookmarks: ImportBookmark[] = [];
  for (const bookmark of value.bookmarks) {
    const parsedBookmark = parseImportBookmark(bookmark);
    if (!parsedBookmark) {
      return undefined;
    }
    bookmarks.push(parsedBookmark);
  }

  return { bookmarks, folders, tags };
}

function parseTagFilterQuery(query: Request["query"]): string[] | undefined {
  const tagValues: string[] = [];

  if (query.tag !== undefined) {
    if (typeof query.tag !== "string" || !isNonEmptyString(query.tag)) {
      return undefined;
    }
    tagValues.push(query.tag);
  }

  if (query.tags !== undefined) {
    if (typeof query.tags !== "string" || !isNonEmptyString(query.tags)) {
      return undefined;
    }
    tagValues.push(...query.tags.split(","));
  }

  const names = tagValues.map((name) => name.trim()).filter((name) => name.length > 0);
  if (tagValues.length > 0 && names.length !== tagValues.length) {
    return undefined;
  }

  return [...new Set(names)];
}

function parsePaginationQuery(query: Request["query"]): Pagination | undefined {
  const page = parsePaginationInteger(query.page, 1, 1, Number.MAX_SAFE_INTEGER);
  const limit = parsePaginationInteger(query.limit, 20, 1, 100);

  if (page === undefined || limit === undefined) {
    return undefined;
  }

  return { page, limit };
}

function parseSearchQuery(query: Request["query"]): SearchQuery | null | undefined {
  if (query.q === undefined) {
    return null;
  }

  if (typeof query.q !== "string" || query.q.length > 200) {
    return undefined;
  }

  const normalized = query.q.trim().toLowerCase();
  if (normalized.length === 0) {
    return null;
  }

  const escaped = escapeLikePattern(normalized);
  return {
    normalized,
    prefixPattern: `${escaped}%`,
    containsPattern: `%${escaped}%`,
  };
}

function parsePaginationInteger(
  value: Request["query"][string],
  defaultValue: number,
  min: number,
  max: number,
): number | undefined {
  if (value === undefined) {
    return defaultValue;
  }

  if (typeof value !== "string" || !/^\d+$/.test(value)) {
    return undefined;
  }

  const parsed = Number(value);
  if (!Number.isSafeInteger(parsed) || parsed < min || parsed > max) {
    return undefined;
  }

  return parsed;
}

function escapeLikePattern(value: string): string {
  return value.replace(/[\\%_]/g, (character) => `\\${character}`);
}

function folderExists(id: number, userId: number): boolean {
  return getFolder(id, userId) !== undefined;
}

function getBookmarksForFolder(folderId: number, userId: number): BookmarkWithTags[] {
  const bookmarks = db
    .prepare(
      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE folder_id = ? AND user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(folderId, userId) as Bookmark[];
  return attachTagsToBookmarks(bookmarks, userId);
}

function tagIdsBelongToUser(tagIds: number[], userId: number): boolean {
  if (tagIds.length === 0) {
    return true;
  }

  const placeholders = tagIds.map(() => "?").join(", ");
  const { count } = db
    .prepare(`SELECT COUNT(*) AS count FROM tags WHERE user_id = ? AND id IN (${placeholders})`)
    .get(userId, ...tagIds) as { count: number };

  return count === tagIds.length;
}

function replaceBookmarkTags(bookmarkId: number, tagIds: number[]): void {
  db.prepare("DELETE FROM bookmark_tags WHERE bookmark_id = ?").run(bookmarkId);

  const insert = db.prepare("INSERT INTO bookmark_tags (bookmark_id, tag_id) VALUES (?, ?)");
  for (const tagId of tagIds) {
    insert.run(bookmarkId, tagId);
  }
}

function attachTagsToBookmarks(bookmarks: Bookmark[], userId: number): BookmarkWithTags[] {
  const tagsByBookmark = new Map<number, Tag[]>();
  for (const bookmark of bookmarks) {
    tagsByBookmark.set(bookmark.id, []);
  }

  }

  if (bookmarks.length === 0) {
    return [];
  }

  const bookmarkIds = bookmarks.map((bookmark) => bookmark.id);
  const placeholders = bookmarkIds.map(() => "?").join(", ");
  const rows = db
    .prepare(
      `
        SELECT
          bookmark_tags.bookmark_id,
          tags.id,
          tags.user_id,
          tags.name,
          tags.created_at,
          tags.updated_at
        FROM bookmark_tags
        INNER JOIN tags ON tags.id = bookmark_tags.tag_id
        WHERE tags.user_id = ? AND bookmark_tags.bookmark_id IN (${placeholders})
        ORDER BY tags.id ASC
      `,
    )
    .all(userId, ...bookmarkIds) as Array<Tag & { bookmark_id: number }>;

  for (const row of rows) {
    const { bookmark_id, ...tag } = row;
    tagsByBookmark.get(bookmark_id)?.push(tag);
  }

  return bookmarks.map((bookmark) => ({
    ...bookmark,
    tags: tagsByBookmark.get(bookmark.id) ?? [],
  }));
}

function getExportPayload(userId: number): ImportPayload {
  const folders = db
    .prepare("SELECT id, name FROM folders WHERE user_id = ? ORDER BY id ASC")
    .all(userId) as ImportFolder[];
  const tags = db.prepare("SELECT id, name FROM tags WHERE user_id = ? ORDER BY id ASC").all(userId) as ImportTag[];
  const bookmarks = db
    .prepare(
      `
        SELECT id, url, title, description, folder_id
        FROM bookmarks
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId) as ExportBookmarkRow[];
  const bookmarksWithTags = attachTagsToBookmarks(
    bookmarks.map((bookmark) => ({
      ...bookmark,
      user_id: userId,
      created_at: "",
      updated_at: "",
    })),
    userId,
  );

  return {
    bookmarks: bookmarksWithTags.map((bookmark) => ({
      id: bookmark.id,
      url: bookmark.url,
      title: bookmark.title,
      description: bookmark.description,
      folder_id: bookmark.folder_id,
      tag_ids: bookmark.tags.map((tag) => tag.id),
      tags: bookmark.tags.map((tag) => ({ id: tag.id, name: tag.name })),
    })),
    folders,
    tags,
  };
}

function arraysEqual(left: number[], right: number[]): boolean {
  if (left.length !== right.length) {
    return false;
  }

  const sortedLeft = [...left].sort((a, b) => a - b);
  const sortedRight = [...right].sort((a, b) => a - b);
  return sortedLeft.every((value, index) => value === sortedRight[index]);
}

function getBookmarkTagIds(bookmarkId: number): number[] {
  const rows = db
    .prepare("SELECT tag_id FROM bookmark_tags WHERE bookmark_id = ? ORDER BY tag_id ASC")
    .all(bookmarkId) as Array<{ tag_id: number }>;
  return rows.map((row) => row.tag_id);
}

function resolveImportTagIds(bookmark: ImportBookmark, tagIdBySourceId: Map<number, number>, tagIdByName: Map<string, number>): number[] {
  const tagIds = new Set<number>();

  for (const sourceTagId of bookmark.tag_ids ?? []) {
    const tagId = tagIdBySourceId.get(sourceTagId);
    if (tagId) {
      tagIds.add(tagId);
    }
  }

  for (const tag of bookmark.tags ?? []) {
    const tagId = tagIdByName.get(tag.name);
    if (tagId) {
      tagIds.add(tagId);
    }
  }

  return [...tagIds];
}

function importPayload(payload: ImportPayload, userId: number): ImportSummary {
  const summary: ImportSummary = { imported: 0, skipped: 0, updated: 0 };
  const folderIdBySourceId = new Map<number, number>();
  const tagIdBySourceId = new Map<number, number>();
  const tagIdByName = new Map<string, number>();
  const now = new Date().toISOString();

  const runImport = db.transaction(() => {
    for (const folder of payload.folders) {
      let targetFolder = getFolderByName(folder.name, userId);
      if (targetFolder) {
        summary.skipped += 1;
      } else {
        const result = db
          .prepare(
            `
              INSERT INTO folders (user_id, name, created_at, updated_at)
              VALUES (?, ?, ?, ?)
            `,
          )
          .run(userId, folder.name, now, now);
        targetFolder = getFolder(Number(result.lastInsertRowid), userId);
        summary.imported += 1;
      }

      if (folder.id && targetFolder) {
        folderIdBySourceId.set(folder.id, targetFolder.id);
      }
    }

    for (const tag of payload.tags) {
      let targetTag = getTagByName(tag.name, userId);
      if (targetTag) {
        summary.skipped += 1;
      } else {
        const result = db
          .prepare(
            `
              INSERT INTO tags (user_id, name, created_at, updated_at)
              VALUES (?, ?, ?, ?)
            `,
          )
          .run(userId, tag.name, now, now);
        targetTag = getTag(Number(result.lastInsertRowid), userId);
        summary.imported += 1;
      }

      if (targetTag) {
        tagIdByName.set(tag.name, targetTag.id);
        if (tag.id) {
          tagIdBySourceId.set(tag.id, targetTag.id);
        }
      }
    }

    for (const bookmark of payload.bookmarks) {
      const normalizedUrl = normalizeUrl(bookmark.url);
      if (!normalizedUrl) {
        throw new Error("invalid import URL after validation");
      }

      const targetFolderId =
        typeof bookmark.folder_id === "number" ? folderIdBySourceId.get(bookmark.folder_id) ?? null : null;
      const targetTagIds = resolveImportTagIds(bookmark, tagIdBySourceId, tagIdByName);
      const existing = getBookmarkByNormalizedUrl(normalizedUrl, userId);

      if (!existing) {
        const result = db
          .prepare(
            `
              INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
              VALUES (?, ?, ?, ?, ?, ?, ?)
            `,
          )
          .run(userId, bookmark.url, bookmark.title, bookmark.description ?? null, targetFolderId, now, now);
        replaceBookmarkTags(Number(result.lastInsertRowid), targetTagIds);
        summary.imported += 1;
        continue;
      }

      const existingTagIds = getBookmarkTagIds(existing.id);
      const needsUpdate =
        existing.title !== bookmark.title ||
        existing.description !== (bookmark.description ?? null) ||
        existing.folder_id !== targetFolderId ||
        !arraysEqual(existingTagIds, targetTagIds);

      if (!needsUpdate) {
        summary.skipped += 1;
        continue;
      }

      db.prepare(
        `
          UPDATE bookmarks
          SET title = ?, description = ?, folder_id = ?, updated_at = ?
          WHERE id = ? AND user_id = ?
        `,
      ).run(bookmark.title, bookmark.description ?? null, targetFolderId, now, existing.id, userId);
      replaceBookmarkTags(existing.id, targetTagIds);
      summary.updated += 1;
    }
  });

  runImport();
  return summary;
}

function buildTagFilterSql(tagNames: string[]): { clause: string; params: string[] } {
  const clauses = tagNames.map(
    () => `
      AND EXISTS (
        SELECT 1
        FROM bookmark_tags
        INNER JOIN tags ON tags.id = bookmark_tags.tag_id
        WHERE bookmark_tags.bookmark_id = bookmarks.id
          AND tags.user_id = bookmarks.user_id
          AND tags.name = ?
      )
    `,
  );

  return {
    clause: clauses.join("\n"),
    params: tagNames,
  };
}

function buildSearchSql(search: SearchQuery | null): {
  clause: string;
  params: string[];
  orderBy: string;
  orderParams: string[];
} {
  if (!search) {
    return {
      clause: "",
      params: [],
      orderBy: "bookmarks.id ASC",
      orderParams: [],
    };
  }

  const matchClause = `
    AND (
      lower(bookmarks.title) LIKE ? ESCAPE '\\'
      OR lower(bookmarks.url) LIKE ? ESCAPE '\\'
      OR lower(COALESCE(bookmarks.description, '')) LIKE ? ESCAPE '\\'
      OR EXISTS (
        SELECT 1
        FROM folders
        WHERE folders.id = bookmarks.folder_id
          AND folders.user_id = bookmarks.user_id
          AND lower(folders.name) LIKE ? ESCAPE '\\'
      )
      OR EXISTS (
        SELECT 1
        FROM bookmark_tags
        INNER JOIN tags ON tags.id = bookmark_tags.tag_id
        WHERE bookmark_tags.bookmark_id = bookmarks.id
          AND tags.user_id = bookmarks.user_id
          AND lower(tags.name) LIKE ? ESCAPE '\\'
      )
    )
  `;

  return {
    clause: matchClause,
    params: [
      search.containsPattern,
      search.containsPattern,
      search.containsPattern,
      search.containsPattern,
      search.containsPattern,
    ],
    orderBy: `
      CASE
        WHEN lower(bookmarks.title) = ? THEN 0
        WHEN lower(bookmarks.title) LIKE ? ESCAPE '\\' THEN 1
        WHEN lower(bookmarks.title) LIKE ? ESCAPE '\\' THEN 2
        ELSE 3
      END ASC,
      bookmarks.id ASC
    `,
    orderParams: [search.normalized, search.prefixPattern, search.containsPattern],
  };
}

function requireUserId(req: Request): number {
  if (typeof req.userId !== "number") {
    throw new Error("authenticated route missing userId");
  }

  return req.userId;
}

function authenticate(req: Request, res: Response, next: NextFunction): Response | void {
  const authorization = req.header("Authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "authentication required" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET);
    const userId = typeof payload === "object" && payload !== null ? payload.userId : undefined;

    if (typeof userId !== "number" || !Number.isInteger(userId) || !getUserById(userId)) {
      return res.status(401).json({ error: "invalid token" });
    }

    req.userId = userId;
    return next();
  } catch {
    return res.status(401).json({ error: "invalid token" });
  }
}

