+      const existing = getBookmarkByNormalizedUrl(normalizedUrl, userId);
+
+      if (!existing) {
+        const result = db
+          .prepare(
+            `
+              INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
+              VALUES (?, ?, ?, ?, ?, ?, ?)
+            `,
+          )
+          .run(userId, bookmark.url, bookmark.title, bookmark.description ?? null, targetFolderId, now, now);
+        replaceBookmarkTags(Number(result.lastInsertRowid), targetTagIds);
+        summary.imported += 1;
+        continue;
+      }
+
+      const existingTagIds = getBookmarkTagIds(existing.id);
+      const needsUpdate =
+        existing.title !== bookmark.title ||
+        existing.description !== (bookmark.description ?? null) ||
+        existing.folder_id !== targetFolderId ||
+        !arraysEqual(existingTagIds, targetTagIds);
+
+      if (!needsUpdate) {
+        summary.skipped += 1;
+        continue;
+      }
+
+      db.prepare(
+        `
+          UPDATE bookmarks
+          SET title = ?, description = ?, folder_id = ?, updated_at = ?
+          WHERE id = ? AND user_id = ?
+        `,
+      ).run(bookmark.title, bookmark.description ?? null, targetFolderId, now, existing.id, userId);
+      replaceBookmarkTags(existing.id, targetTagIds);
+      summary.updated += 1;
+    }
+  });
+
+  runImport();
+  return summary;
+}
